module xorx #(parameter [31:0] b = 0) (input [31:0] a, output [31:0] y);
	assign y = a ^ b;
endmodule

module top(input [31:0] a, output [31:0] y);
	localparam N = 2000;
	wire [31:0] s[0:N];
	generate
		genvar i;
		for (i = 0; i < N; i = i + 1'b1) begin
			xorx #(.b(i)) xor_i(.a(s[i]), .y(s[i+1]));
		end
	endgenerate
	assign s[0] = a;
	assign y = s[N];
endmodule

(* noflatten *) module sub(output [31:0] y);
	parameter P = 0;
	assign y = P;
endmodule

module top(output [31:0] y);
	genvar i;
	wire [31:0] w[0:999];
	for (i = 0; i < 1000; i = i + 1) begin
		sub #(.P(i)) s(.y(w[i]));
	end
	assign y = w[999];
endmodule
